import{_ as b,o as e,c as a,j as p,a as t,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"小山猪","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/7.载具及随从/随从/7.系列随从/宝可梦系列/1.宝可梦/小山猪.md","filePath":"4.资源分区/7.物品与装备/7.载具及随从/随从/7.系列随从/宝可梦系列/1.宝可梦/小山猪.md"}'),s={name:"4.资源分区/7.物品与装备/7.载具及随从/随从/7.系列随从/宝可梦系列/1.宝可梦/小山猪.md"};function o(d,r,l,_,i,c){return e(),a("div",null,[...r[0]||(r[0]=[p("h1",{id:"小山猪",tabindex:"-1"},[t("小山猪 "),p("a",{class:"header-anchor",href:"#小山猪","aria-label":'Permalink to "小山猪"'},"​")],-1),p("table",{class:"bannerparthead"},[p("tbody",null,[p("tr",{id:"hdr"},[p("td",{class:"runninghead",nowrap:""},"灵魂蓝调012")])])],-1),n('<h1 id="小山猪-1" tabindex="-1">小山猪 <a class="header-anchor" href="#小山猪-1" aria-label="Permalink to &quot;小山猪&quot;">​</a></h1><p>小山猪</p><p>D+500<br> 独立随从</p><p>小山猪，小猪宝可梦，为了寻找食物，会用鼻子摩擦地面并进行挖掘，偶尔会挖到温泉。<br> 系别：地面+冰系</p><p>▓▓▓▓属性<br> ▓▓生理属性<br> ■力量6<br> ■敏捷4<br> ■耐力6<br> ▓▓心智属性<br> ■智力2<br> ■感知4<br> ■决心2<br> ▓▓互动属性<br> ■风度2<br> ■操控2<br> ■沉着4</p><p>▓▓▓▓技能<br> ▓▓生理系<br> ■运动5-投掷5-反射3<br> ■求生3-强韧3-动物沟通3<br> ■射击1<br> ■武技5-牙5</p><p>▓▓心智系<br> ■学识3-魔法3<br> ■器用1<br> ■手艺1<br> ■专注3-意志3</p><p>▓▓互动系<br> ■洞察3<br> ■隐秘1<br> ■表达1<br> ■社交1</p><p>▓▓▓▓衍生属性值<br> ▓体积 1<br> ▓速度 11米<br> ▓先攻 8<br> ▓防御 4<br> ▓生命值 15<br> ▓意志力池 6<br> ▓意志 8+1<br> ▓反射 12+2/16+2（当你选择了雪隐且天气为冰雹天气时）<br> ▓强韧 12+2<br> ▓侦查 7<br> ▓敏感范围 80米</p><p>▓▓▓▓关于属性上的附加成功：<br> 力量上的每1点附加成功会为其提供力量检定上的3DP增强加值，可携带物品体积额外提升4点<br> 敏捷上的附加成功达到1点时会获得一个花招动作，达到4点时会将基础的移动动作升级为杂技动作，敏捷上的每1点附加成功会提供3米额外移速<br> 耐力上的每1点附加成功会为其提供5点额外的生命值</p><p>智力上的每1点附加成功会为其提供每天一次，重投某个骰子的能力，但无论其结果如何，都必须接受那个骰子的结果<br> 感知上的每1点附加成功会为其提供额外的20米敏感范围及洞察技能检定上的1点增强加值<br> 决心上的每1点附加成功会为其提供2点额外的意志池上限，每达到2点就会赠送2点专注技能检定上的增强加值</p><p>风度上的每1点附加成功会为其提供5点额外的外貌上升，并额外提供社交/表达技能检定上的1点增强加值<br> 操控上的每1点附加成功会为其提供1点操控检定上的附加成功与所有互动技能检定上的1点表现加值<br> 沉着上的每1点附加成功会为其提供在先攻检定上的额外一个十面骰</p><p>▓▓▓▓攻击预设：<br> 普通攻击预设：力量+武技+牙+天生武器伤害=19+3造成严重穿刺伤害。</p><p>宝可梦技艺近战攻击预设：力量+武技+牙+天生武器伤害+训练家专业：指挥+技能效果。</p><p>宝可梦技艺投掷攻击预设：力量+运动+投掷+训练家专业：指挥+技能效果。</p><p>宝可梦技艺施法攻击预设：感知+学识+魔法+训练家专业：指挥+技能效果。</p><p>以上三种攻击预设只在宝可梦学习了具有该预设模式的技艺后方可使用。</p><p>▓▓▓▓防御预设：基础防御4 5点雷电能量抗力 【5点火焰和冻寒能量抗力（当你选择了厚脂肪特性）】【闪避防御6+1（当你选择了雪隐特性且天气为冰雹时）】</p><p>▓▓▓▓性别：公/母（购买时选定其中一种，选定之后无法更改）</p><p>▓▓▓▓特性：</p><p>【长牙未露不可谓之不利】：虽然此时小山猪的牙还只有雏形，但比起它的小小体型来说，那对长牙已经是令人生畏的武器。小山猪的牙齿视为3L的天生武器。</p><p>【地面系宝可梦】：地面系宝可梦是天生的电系克星，小山猪获得了5点雷电能量抗力。</p><p>【厚脂肪】：拥有厚脂肪特性的宝可梦在耐热和抗寒能力上的表现要远超其他宝可梦，小山猪获得5点火焰能量抗力和5点冻寒能量抗力。</p><p>【雪隐】：作为诞生于冰雪能量中的宝可梦，每当天气为冰雹天气时，小山猪获得4点反射豁免的增强加值，6点闪避防御以及1点基于闪避防御的附加成功。</p><p>【迟钝】：拥有迟钝特性的宝可梦在抵御来自于情绪等负面影响的异常点数时拥有更杰出的表现，小山猪不会受到魅惑点数带来的减值及严重状态。</p><p>以上三种特性仅在购买小山猪时可以选择其中一种生效，一旦选择便无法更改。</p><p>▓▓▓▓装备位：</p><p>▓▓▓▓亲密度： /250</p><p>▓▓▓▓可学习技能：<br> 一般系技能：泰山压顶 破坏光线 替身 守住 硬撑 舍身冲撞</p><p>地面系技能：地震 重踏 十万马力 跺脚 流沙深渊 挖洞 地裂 大地之力</p><p>岩石系技能：尖石攻击 岩崩 岩石封锁 岩石暴击 原始之力</p><p>冰系技能：冰柱坠击 冰砾 冰冻之风 暴风雪 冰冻光束 冰锥</p><p>格斗系技能：蛮力 扑击</p><p>超能系技能：光墙 反射壁 瞬间失忆 睡觉</p><p>恶系技能：咬住</p><p>水系技能：求雨</p><p>▓▓▓▓已学习技能：</p><p>▓▓▓▓购买记录：</p><p>【长毛猪】由小山猪支付10xp进化而来<br> 独立随从<br> 长毛猪视为C级召唤物。<br> 长毛猪仅能由小山猪进化而来，不可单独购买</p><p>长毛猪，野猪宝可梦，小山猪的进化型，由于被长长的体毛所覆盖，所以看不清眼前的情况，只会一个劲的来回猛撞。</p><p>系别：地面+冰系</p><p>▓▓▓▓属性<br> ▓▓生理属性<br> ■力量11<br> ■敏捷9<br> ■耐力11<br> ▓▓心智属性<br> ■智力6<br> ■感知9<br> ■决心6<br> ▓▓互动属性<br> ■风度6<br> ■操控6<br> ■沉着9</p><p>▓▓▓▓技能<br> ▓▓生理系<br> ■运动8-投掷8-反射5<br> ■求生5-强韧5<br> ■射击1<br> ■武技8-牙8</p><p>▓▓心智系<br> ■学识5-魔法5<br> ■器用1<br> ■手艺1<br> ■专注5-意志5</p><p>▓▓互动系<br> ■洞察5<br> ■隐秘1<br> ■表达1<br> ■社交1</p><p>▓▓▓▓衍生属性值<br> ▓体积 5<br> ▓速度 28米<br> ▓先攻 18<br> ▓防御 9+1<br> ▓生命值 26<br> ▓意志力池 17<br> ▓意志 17+3<br> ▓反射 23+4/33+4（当你选择雪隐特性且天气为冰雹时）<br> ▓强韧 22+4<br> ▓侦查 15+2<br> ▓敏感范围 200米</p><p>▓▓▓▓关于属性上的附加成功：<br> 力量上的每1点附加成功会为其提供力量检定上的3DP增强加值，可携带物品体积额外提升4点<br> 敏捷上的附加成功达到1点时会获得一个花招动作，达到4点时会将基础的移动动作升级为杂技动作，敏捷上的每1点附加成功会提供3米额外移速<br> 耐力上的每1点附加成功会为其提供5点额外的生命值</p><p>智力上的每1点附加成功会为其提供每天一次，重投某个骰子的能力，但无论其结果如何，都必须接受那个骰子的结果<br> 感知上的每1点附加成功会为其提供额外的20米敏感范围及洞察技能检定上的1点增强加值<br> 决心上的每1点附加成功会为其提供2点额外的意志池上限，每达到2点就会赠送2点专注技能检定上的增强加值</p><p>风度上的每1点附加成功会为其提供5点额外的外貌上升，并额外提供社交/表达技能检定上的1点增强加值<br> 操控上的每1点附加成功会为其提供1点操控检定上的附加成功与所有互动技能检定上的1点表现加值<br> 沉着上的每1点附加成功会为其提供在先攻检定上的额外一个十面骰</p><p>▓▓▓▓攻击预设：<br> 普通攻击预设：力量+武技+牙+天生武器伤害=30+4造成严重穿刺伤害</p><p>宝可梦技艺近战攻击预设：力量+武技+牙+天生武器伤害+训练家专业：指挥+技能效果。</p><p>宝可梦技艺投掷攻击预设：力量+运动+投掷+训练家专业：指挥+技能效果。</p><p>宝可梦技艺施法攻击预设：感知+学识+魔法+训练家专业：指挥+技能效果。</p><p>以上三种攻击预设只在宝可梦学习了具有该预设模式的技艺后方可使用。</p><p>▓▓▓▓防御预设：基础防御9+1 雷电能量抗力10 【天生防御6+1 火焰能量抗力5 冻寒能量抗力5（当你选择的特性是厚脂肪时生效）】【洞察防御6+1 闪避防御6+1（当你选择的特性是雪隐且天气为冰雹时生效）】</p><p>▓▓▓▓性别：公/母（购买时选定其中一种，选定之后无法更改）</p><p>▓▓▓▓特性：<br> 【提升：地面系宝可梦】：地面系宝可梦是天生的电系克星，长毛猪再获得5点雷电能量抗力。</p><p>【提升：厚脂肪】：此时拥有厚脂肪特性的长毛猪已不仅仅是在抗寒抗热上表现出色了，它厚厚的脂肪同样可以为他提供防御。长毛猪获得6点天生防御以及1点基于天生防御的附加成功。</p><p>【提升：雪隐】：同冰雪能量相伴多年的宝可梦，对冰雹天气的喜爱远超其他宝可梦所能及，当天气处于冰雹天气时，长毛猪再获得6点反射豁免的增强加值，6点洞察防御以及1点基于洞察防御的附加成功。</p><p>【提升：迟钝】：拥有迟钝特性的宝可梦在抵御来自于情绪等负面影响的异常点数时拥有更杰出的表现，此时的长毛猪已经不会陷入A级及以下的迷情状态。</p><p>▓▓▓▓装备位：</p><p>▓▓▓▓亲密度： /250</p><p>▓▓▓▓可学习技能：</p><p>同【小山猪】。</p><p>▓▓▓▓已学习技能：</p><p>▓▓▓▓购买记录：</p><p>【象牙猪】由长毛猪支付20xp进化而来<br> 另外的进化方式：在长毛猪掌握了招式原始之力后进化而来（ST选开）<br> 独立随从<br> 象牙猪视为B级召唤物<br> 象牙猪仅能由长毛猪进化而来，不可单独购买</p><p>象牙猪，双牙宝可梦，长毛猪的进化型，有着用冰制成的强大牙齿，冰河时期结束后，由于气候回暖，导致数量减少。</p><p>系别：地面+冰系</p><p>▓▓▓▓属性<br> ▓▓生理属性<br> ■力量16<br> ■敏捷14<br> ■耐力16<br> ▓▓心智属性<br> ■智力11<br> ■感知14<br> ■决心11<br> ▓▓互动属性<br> ■风度11<br> ■操控11<br> ■沉着14</p><p>▓▓▓▓技能<br> ▓▓生理系<br> ■运动11-投掷11-反射8<br> ■求生8-强韧8<br> ■射击1<br> ■武技11-牙11</p><p>▓▓心智系<br> ■学识8-魔法8<br> ■器用1<br> ■手艺1<br> ■专注8-意志8</p><p>▓▓互动系<br> ■洞察8<br> ■隐秘1<br> ■表达1<br> ■社交1</p><p>▓▓▓▓衍生属性值<br> ▓体积 7<br> ▓速度 43米<br> ▓先攻 28<br> ▓防御 14+2<br> ▓生命值 38<br> ▓意志力池 29<br> ▓意志 31+5/31+6（若你选择特性为迟钝时）<br> ▓反射 34+6/56+6（若你选择特性为雪隐且天气是冰雹天气时）<br> ▓强韧 33+6/44+6（若你选择特性为厚脂肪）<br> ▓侦查 26+5<br> ▓敏感范围 320米</p><p>▓▓▓▓关于属性上的附加成功：<br> 力量上的每1点附加成功会为其提供力量检定上的3DP增强加值，可携带物品体积额外提升4点<br> 敏捷上的附加成功达到1点时会获得一个花招动作，达到4点时会将基础的移动动作升级为杂技动作，敏捷上的每1点附加成功会提供3米额外移速<br> 耐力上的每1点附加成功会为其提供5点额外的生命值</p><p>智力上的每1点附加成功会为其提供每天一次，重投某个骰子的能力，但无论其结果如何，都必须接受那个骰子的结果<br> 感知上的每1点附加成功会为其提供额外的20米敏感范围及洞察技能检定上的1点增强加值<br> 决心上的每1点附加成功会为其提供2点额外的意志池上限，每达到2点就会赠送2点专注技能检定上的增强加值</p><p>风度上的每1点附加成功会为其提供5点额外的外貌上升，并额外提供社交/表达技能检定上的1点增强加值<br> 操控上的每1点附加成功会为其提供1点操控检定上的附加成功与所有互动技能检定上的1点表现加值<br> 沉着上的每1点附加成功会为其提供在先攻检定上的额外一个十面骰</p><p>▓▓▓▓攻击预设：<br> 普通攻击预设：力量+武技+牙+天生武器伤害=52+7造成严重穿刺伤害</p><p>宝可梦技艺近战攻击预设：力量+武技+牙+天生武器伤害+训练家专业：指挥+技能效果。</p><p>宝可梦技艺投掷攻击预设：力量+运动+投掷+训练家专业：指挥+技能效果。</p><p>宝可梦技艺施法攻击预设：感知+学识+魔法+训练家专业：指挥+技能效果。</p><p>以上三种攻击预设只在宝可梦学习了具有该预设模式的技艺后方可使用。</p><p>▓▓▓▓防御预设：基础防御14+2 雷电能量抗力20 【天生防御12+2 火焰能量抗力5 冻寒能量抗力5（当你选择的特性是厚脂肪时生效）】【力场防御12+1 洞察防御6+1 闪避防御6+1（当你选择的特性是雪隐且天气为冰雹时生效）】</p><p>▓▓▓▓性别：公/母（购买时选定其中一种，选定之后无法更改）</p><p>▓▓▓▓特性：<br> 【提升：地面系宝可梦】：地面系宝可梦是天生的电系克星，象牙猪再获得10点雷电能量抗力。</p><p>【提升：厚脂肪】：此时拥有厚脂肪特性的象牙猪已不仅仅是在抗寒抗热上表现出色了，它厚厚的脂肪同样可以为他提供防御。象牙猪再获得6点天生防御以及1点基于天生防御的附加成功，并获得10点强韧豁免上的增强加值。</p><p>【提升：雪隐】：同冰雪能量相伴多年的宝可梦，对冰雹天气的喜爱远超其他宝可梦所能及，当天气处于冰雹天气时，象牙猪再获得12点反射豁免的增强加值，12点力场防御以及1点基于力场防御的附加成功。</p><p>【提升：迟钝】：拥有迟钝特性的宝可梦在抵御来自于情绪等负面影响的异常点数时拥有更杰出的表现，此时的象牙猪可以免疫恐惧、沮丧、剧痛三种异常点数带来的减值及严重状态，并获得1点意志豁免的附加成功。</p><p>▓▓▓▓装备位：</p><p>▓▓▓▓亲密度： /250</p><p>▓▓▓▓可学习技能：</p><p>同【长毛猪】</p><p>▓▓▓▓已学习技能：</p><p>▓▓▓▓购买记录：</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',96)])])}const m=b(s,[["render",o]]);export{f as __pageData,m as default};
